15	  public getDigitalOceanPublicURL(): string {
16	    return this.configService.DIGITAL_OCEAN_PUBLIC_URL;
17	  }
18	
19	  public buildPublicUrl(fileNameOrUrl: string): string {
20	    if (!fileNameOrUrl) {
21	      return fileNameOrUrl;
22	    }
23	
24	    const baseUrl = this.getDigitalOceanPublicURL().replace(/\/+$/, '');
25	
26	    if (fileNameOrUrl.startsWith(`${baseUrl}/`)) {
27	      return fileNameOrUrl;
28	    }
29	
30	    // Repair full URLs saved without a slash between host and path.
31	    if (fileNameOrUrl.startsWith(baseUrl)) {
32	      return this.buildPublicUrl(fileNameOrUrl.slice(baseUrl.length));
33	    }
34	
35	    // Leave other absolute URLs (CDN placeholders, external links) unchanged.
36	    if (/^https?:\/\//i.test(fileNameOrUrl)) {
37	      return fileNameOrUrl;
38	    }
39	
40	    const normalizedFileName = fileNameOrUrl.replace(/^\/+/, '');
41	    return `${baseUrl}/${normalizedFileName}`;
42	  }
