44	  async saveToDigitalOceanAndDB(fileName: string, contentType: string, file: File): Promise<any> {
45	    const res: any = await this.api.getPreSignedUrl({ fileName, contentType }).pipe(first()).toPromise();
46	    const signedUrl = res.signedUrl;
47	    const headers = new Headers({ 'Content-Type': contentType, 'x-amz-acl': 'public-read' });
48	    const putConfig: any = { method: 'PUT', body: file, headers: headers };
49	    return fetch(signedUrl, putConfig);
50	  }
51	
52	  resizeImage(file: File, fileName: string): Promise<File> {
53	    return new Promise(async (resolve) => {
54	      const reader = new FileReader();
55	      reader.readAsDataURL(file);
56	      reader.onload = async () => {
57	        const image = new Image();
58	        image.onload = async function () {
59	          const canvas = document.createElement('canvas');
60	          canvas.width = 200;
61	          canvas.height = 200;
62	          const ctx = canvas.getContext('2d');
63	          if (ctx != null) {
64	            ctx.drawImage(image, 0, 0, 200,200);
65	          }
66	          const data = canvas.toDataURL('image/jpeg', 1);
67	          const response = await fetch(data);
68	          const blob = await response.blob();
69	          const file = new File([blob], fileName, { type: "image/jpeg" })
70	          resolve(file);
71	        };
72	        image.src = reader.result as string;
73	      }
74	    });
75	  }
76	}
