16	  // ===========================================================================
17	  // Reference-data cache  (added 2026-06-22 — page-load performance)
18	  // ---------------------------------------------------------------------------
19	  // WHAT: Static-ish reference lists (RFQ statuses, groups, customers, delivery
20	  // locations, steps, CBM, licenses, company codes, FOB countries, vendors, and
21	  // the RFQ *detail* grid headers) used to be re-fetched from the API on every
22	  // page navigation — and, for the detail grid headers / FOB countries, on every
23	  // single master-row expansion. We now memoize each as a hot, replayed
24	  // observable so the underlying GET fires at most once per session (until
25	  // explicitly invalidated after a related mutation).
26	  //
27	  // WHY shareReplay({ bufferSize: 1, refCount: false }): keep the last response
28	  // and replay it to later subscribers without re-issuing the request;
29	  // refCount:false keeps the value cached even when the subscriber count drops
30	  // to zero, so navigating away and back reuses it.
31	  //
32	  // SAFETY:
33	  //  - Each subscriber receives a shallow COPY of arrays, so a consumer that
34	  //    sorts/pushes the list in place cannot corrupt the shared cache.
35	  //  - Errors are NOT cached: on failure the entry is evicted so the next call
36	  //    retries (a transient 500 must not poison the list for the whole session).
37	  //
38	  // INVALIDATION: call clearRefCache(key) after the matching create/update/delete
39	  // so the next read re-fetches. The relevant mutation methods below already do
40	  // this via tap(). clearRefCache() with no key drops everything (use on logout).
41	  //
42	  // >>> HOW TO UNDO (if caching ever causes stale-data bugs): see
43	  //     docs/performance-caching.md §"Reverting". In short: revert each wrapped
44	  //     getter to a plain `return this.http.get(...)` and delete this block —
45	  //     call sites are unchanged, so reverting the service alone fully restores
46	  //     the old always-fetch behavior.
47	  // ===========================================================================
48	  private refCache = new Map<string, Observable<any>>();
49	
50	  private getCached<T>(key: string, factory: () => Observable<T>): Observable<T> {
51	    let cached = this.refCache.get(key);
52	    if (!cached) {
53	      cached = factory().pipe(
54	        // Do not poison the cache on a transient failure: evict + rethrow so the
55	        // next subscriber creates a fresh request.
56	        catchError((err) => { this.refCache.delete(key); return throwError(() => err); }),
57	        shareReplay({ bufferSize: 1, refCount: false }),
58	      );
59	      this.refCache.set(key, cached);
60	    }
61	    // Defensive shallow copy so in-place mutation by a consumer can't corrupt the cache.
62	    return (cached as Observable<T>).pipe(map((v: any) => (Array.isArray(v) ? [...v] : v)));
63	  }
